#include<stdio.h>
#include<string.h>
char a[1001][12],b[1001][12];int na=0,nb=0;
int eq(char v1[][12],int n1,int i1,char v2[][12],int n2,int i2){
  int e1=i1>=n1||strcmp(v1[i1],"N")==0;
  int e2=i2>=n2||strcmp(v2[i2],"N")==0;
  if(e1&&e2)return 1;if(e1||e2)return 0;
  return eq(v1,n1,2*i1+1,v2,n2,2*i2+1)&&eq(v1,n1,2*i1+2,v2,n2,2*i2+2);
}
int main(){while(scanf("%s",a[na])==1)na++;while(scanf("%s",b[nb])==1)nb++;puts(eq(a,na,0,b,nb,0)?"OUI":"NON");}
